// Build the file
let out = '';
out += `export interface AlbumSeedData {\n  title: string;\n  artistName: string;\n  releaseYear: number;\n  genres: string[];\n  subgenres: string[];\n  impactTier: "Landmark" | "Essential" | "Notable";\n  impactScore: number;\n  summary: string;\n  links: {\n    spotify?: string;\n    apple?: string;\n    youtube?: string;\n  };\n}\n\n`;

out += `function buildLinks(artist: string, title: string) {\n  const q = encodeURIComponent(artist + " " + title);\n  return {\n    spotify: \`https://open.spotify.com/search/\${q}\`,\n    apple: \`https://music.apple.com/us/search?term=\${q}\`,\n    youtube: \`https://music.youtube.com/search?q=\${q}\`,\n  };\n}\n\n`;

out += 'export const albums: AlbumSeedData[] = [\n';
for (const a of R) {
  const [title, artist, year, genres, subgenres, tier, score, summary] = a;
  out += `  {\n`;
  out += `    title: ${JSON.stringify(title)},\n`;
  out += `    artistName: ${JSON.stringify(artist)},\n`;
  out += `    releaseYear: ${year},\n`;
  out += `    genres: ${JSON.stringify(genres)},\n`;
  out += `    subgenres: ${JSON.stringify(subgenres)},\n`;
  out += `    impactTier: ${JSON.stringify(tier)},\n`;
  out += `    impactScore: ${score},\n`;
  out += `    summary: ${JSON.stringify(summary)},\n`;
  out += `    links: buildLinks(${JSON.stringify(artist)}, ${JSON.stringify(title)}),\n`;
  out += `  },\n`;
}
out += '];\n\n';

// genre hero/canon maps
// Find indices by genre
function findByGenre(slug) {
  const idxs = [];
  for (let i = 0; i < R.length; i++) {
    if (R[i][3].includes(slug)) idxs.push(i);
  }
  return idxs;
}

function sortByScore(idxs) {
  return idxs.sort((a,b) => R[b][6] - R[a][6]);
}

const parents = ["rock","hip-hop","electronic","jazz","rnb-soul","pop","metal","folk-country"];
out += '/** Maps parent genre slug to album indices for "Start Here" hero section (up to 12) */\n';
out += 'export const genreHeroAlbums: Record<string, number[]> = {\n';
for (const g of parents) {
  const sorted = sortByScore(findByGenre(g));
  out += `  "${g}": ${JSON.stringify(sorted.slice(0,12))},\n`;
}
out += '};\n\n';

out += '/** Maps parent genre slug to album indices for "Canon" section (up to 24) */\n';
out += 'export const genreCanonAlbums: Record<string, number[]> = {\n';
for (const g of parents) {
  const sorted = sortByScore(findByGenre(g));
  out += `  "${g}": ${JSON.stringify(sorted.slice(0,24))},\n`;
}
out += '};\n';

fs.writeFileSync('/Users/richardyuh/src/music-museum/prisma/data/albums.ts', out);
console.log('Done. Albums: ' + R.length);
// Count by tier
const tiers = {};
for (const a of R) { tiers[a[5]] = (tiers[a[5]]||0)+1; }
console.log('Tiers:', JSON.stringify(tiers));
// Count by parent genre
for (const g of parents) {
  console.log(g + ': ' + findByGenre(g).length);
}
